  --color-primary: #0000FF;
  --color-primary-hover: #3366FF;
  --color-secondary: #000000;
  --color-background: #000000;
  --color-accent: #3366FF;
  --color-text-on-primary: #FFFFFF;
  --color-text-on-secondary: #FFFFFF;
